package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;
@Entity @Table(name="items_devolucion") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class ItemDevolucion{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="devolucion_id")private Devolucion devolucion;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="item_venta_id")private ItemVenta itemVenta;@Column(nullable=false)private int cantidad;@Column(nullable=false,precision=14,scale=2)private BigDecimal subtotal;}
